/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
class Solution {
    public ListNode deleteDuplicates(ListNode head) {
        // Handle edge cases: empty list or list with only one node
        if (head == null || head.next == null) {
            return head;
        }

        ListNode current = head;

        // Iterate through the list until current or current.next is null
        while (current != null && current.next != null) {
            // If current node's value is the same as the next node's value
            if (current.val == current.next.val) {
                // Skip the duplicate node by pointing current.next to current.next.next
                // We do NOT advance 'current' here because the new current.next
                // might also be a duplicate of current.val
                current.next = current.next.next;
            } else {
                // If values are different, no duplicate found, move to the next node
                current = current.next;
            }
        }

        return head;
    }
}

