class Solution {
    private int maxLength = 0;
    private int start = 0;

    public String longestPalindrome(String s) {
        if (s == null || s.length() < 1) {
            return "";
        }

        for (int i = 0; i < s.length(); i++) {
            // 考虑以 s[i] 为中心的奇数长度回文串
            expandAroundCenter(s, i, i);
            // 考虑以 s[i] 和 s[i+1] 之间的空隙为中心的偶数长度回文串
            expandAroundCenter(s, i, i + 1);
        }

        return s.substring(start, start + maxLength);
    }

    private void expandAroundCenter(String s, int left, int right) {
        // 当 left 和 right 在字符串范围内，并且 s[left] == s[right] 时，继续向外扩展
        while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
            left--;
            right++;
        }

        // 循环结束后，s[left+1 ... right-1] 是一个回文串
        // 计算当前回文串的长度
        int currentLength = right - 1 - (left + 1) + 1; // 等价于 right - 1 - left

        // 如果当前回文串更长，则更新最长回文串的起始位置和长度
        if (currentLength > maxLength) {
            maxLength = currentLength;
            start = left + 1; // 回文串的实际起始位置是 left + 1
        }
    }
}

