class Solution {
    public int trap(int[] height) {
        if (height == null || height.length < 3) {
            return 0;
        }

        int left = 0;
        int right = height.length - 1;
        int leftMax = 0; // 记录从左边到当前left指针位置的最高墙高度
        int rightMax = 0; // 记录从右边到当前right指针位置的最高墙高度
        int trappedWater = 0;

        while (left < right) {
            // 总是处理较矮的那一侧，因为较矮的一侧决定了当前能积水的上限
            if (height[left] < height[right]) {
                // 如果左边的墙更矮，那么当前left位置能积水的上限由leftMax决定
                if (height[left] >= leftMax) {
                    // 如果当前墙比leftMax高，更新leftMax
                    leftMax = height[left];
                } else {
                    // 否则，当前位置可以积水，水量为 leftMax - height[left]
                    trappedWater += leftMax - height[left];
                }
                left++; // 移动左指针
            } else {
                // 如果右边的墙更矮或相等，那么当前right位置能积水的上限由rightMax决定
                if (height[right] >= rightMax) {
                    // 如果当前墙比rightMax高，更新rightMax
                    rightMax = height[right];
                } else {
                    // 否则，当前位置可以积水，水量为 rightMax - height[right]
                    trappedWater += rightMax - height[right];
                }
                right--; // 移动右指针
            }
        }
        return trappedWater;
    }
}
