import java.util.List;
import java.util.Arrays;

class Solution {
    public int minimumDistance(List<Integer> arr1, List<Integer> arr2, List<Integer> arr3) {
        int n1 = arr1.size();
        int n2 = arr2.size();
        int n3 = arr3.size();

        int p1 = 0, p2 = 0, p3 = 0;
        int minDistance = Integer.MAX_VALUE;

        while (p1 < n1 && p2 < n2 && p3 < n3) {
            int val1 = arr1.get(p1);
            int val2 = arr2.get(p2);
            int val3 = arr3.get(p3);

            // Case 1: All three values are equal
            if (val1 == val2 && val2 == val3) {
                // Found three equal elements. Calculate the distance based on their indices.
                // The distance formula |idx1 - idx2| + |idx2 - idx3| + |idx3 - idx1|
                // simplifies to 2 * (max(idx1, idx2, idx3) - min(idx1, idx2, idx3)).
                int currentMaxIdx = Math.max(p1, Math.max(p2, p3));
                int currentMinIdx = Math.min(p1, Math.min(p2, p3));
                minDistance = Math.min(minDistance, 2 * (currentMaxIdx - currentMinIdx));

                // To find other combinations for the current common value or new common elements,
                // we must advance one of the pointers. To ensure we explore all relevant index
                // combinations and move efficiently, we advance the pointer that points to the
                // smallest index among p1, p2, p3.
                if (p1 <= p2 && p1 <= p3) {
                    p1++;
                } else if (p2 <= p1 && p2 <= p3) {
                    p2++;
                } else { // p3 is the smallest index
                    p3++;
                }
            } 
            // Case 2: Values are not all equal. Advance the pointer pointing to the smallest value
            // to try and make them equal. This is the standard three-pointer logic for sorted arrays.
            else {
                if (val1 <= val2 && val1 <= val3) {
                    p1++;
                } else if (val2 <= val1 && val2 <= val3) {
                    p2++;
                } else { // val3 is the smallest value
                    p3++;
                }
            }
        }

        // If minDistance is still Integer.MAX_VALUE, it means no common elements were found.
        return minDistance == Integer.MAX_VALUE ? -1 : minDistance;
    }
}
