class Solution {
    public boolean checkInclusion(String s1, String s2) {
        if (s1.length() > s2.length()) {
            return false;
        }

        int[] s1Freq = new int[26]; // Frequency map for s1
        int[] windowFreq = new int[26]; // Frequency map for the current window in s2

        // Initialize s1Freq and the first windowFreq
        for (int i = 0; i < s1.length(); i++) {
            s1Freq[s1.charAt(i) - 'a']++;
            windowFreq[s2.charAt(i) - 'a']++;
        }

        // 'matches' counts how many characters (a-z) have exactly the same frequency
        // in s1Freq and windowFreq.
        int matches = 0;
        for (int i = 0; i < 26; i++) {
            if (s1Freq[i] == windowFreq[i]) {
                matches++;
            }
        }

        // If the first window is a permutation, return true
        if (matches == 26) {
            return true;
        }

        // Slide the window
        for (int i = s1.length(); i < s2.length(); i++) {
            int rightCharIdx = s2.charAt(i) - 'a';
            int leftCharIdx = s2.charAt(i - s1.length()) - 'a';

            // Update matches for the character leaving the window
            // If frequencies matched before removal, they won't match after, so decrement matches.
            if (s1Freq[leftCharIdx] == windowFreq[leftCharIdx]) {
                matches--;
            }
            windowFreq[leftCharIdx]--;
            // If frequencies match after removal, increment matches.
            // This handles cases where s1Freq[char] was 0 and windowFreq[char] was 1, now both are 0.
            if (s1Freq[leftCharIdx] == windowFreq[leftCharIdx]) {
                matches++;
            }

            // Update matches for the character entering the window
            // If frequencies matched before addition, they won't match after, so decrement matches.
            if (s1Freq[rightCharIdx] == windowFreq[rightCharIdx]) {
                matches--;
            }
            windowFreq[rightCharIdx]++;
            // If frequencies match after addition, increment matches.
            if (s1Freq[rightCharIdx] == windowFreq[rightCharIdx]) {
                matches++;
            }

            // If all 26 characters have matching frequencies, we found a permutation
            if (matches == 26) {
                return true;
            }
        }

        return false;
    }
}

