import java.util.Stack;
import java.util.HashMap;

class Solution {
    public boolean isValid(String s) {
        // 使用HashMap存储括号对，方便查找匹配
        HashMap<Character, Character> mappings = new HashMap<>();
        mappings.put(')', '(');
        mappings.put('}', '{');
        mappings.put(']', '[');

        // 使用栈来存储遇到的左括号
        Stack<Character> stack = new Stack<>();

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);

            // 如果当前字符是右括号
            if (mappings.containsKey(c)) {
                // 栈为空，或者栈顶元素与当前右括号不匹配，则无效
                // stack.empty() 检查栈是否为空，防止在空栈上执行pop操作
                // stack.pop() 获取并移除栈顶元素，与当前右括号的匹配左括号进行比较
                char topElement = stack.empty() ? '#' : stack.pop();
                if (topElement != mappings.get(c)) {
                    return false;
                }
            } else {
                // 如果是左括号，则压入栈中
                stack.push(c);
            }
        }

        // 遍历完所有字符后，如果栈为空，说明所有括号都已正确匹配
        return stack.empty();
    }
}

