```java
import java.util.Deque;
import java.util.ArrayDeque;

class Solution {
    public int evalRPN(String[] tokens) {
        // 使用Deque作为栈，ArrayDeque是实现Deque接口的双端队列，效率高
        Deque<Integer> stack = new ArrayDeque<>();

        for (String token : tokens) {
            switch (token) {
                case "+":
                    // 弹出两个操作数，执行加法，结果入栈
                    stack.push(stack.pop() + stack.pop());
                    break;
                case "-":
                    // 注意减法和除法的操作数顺序：先弹出的为右操作数，后弹出的为左操作数
                    int b = stack.pop(); // 第二个操作数
                    int a = stack.pop(); // 第一个操作数
                    stack.push(a - b);
                    break;
                case "*":
                    // 弹出两个操作数，执行乘法，结果入栈
                    stack.push(stack.pop() * stack.pop());
                    break;
                case "/":
                    // 注意减法和除法的操作数顺序
                    int divisor = stack.pop(); // 除数
                    int dividend = stack.pop(); // 被除数
                    stack.push(dividend / divisor);
                    break;
                default:
                    // 如果不是操作符，则认为是数字，将其转换为整数并入栈
                    stack.push(Integer.parseInt(token));
                    break;
            }
        }

        // 最终栈中剩下的唯一元素就是表达式的结果
        return stack.pop();
    }
}
