import java.util.Arrays;

class Solution {

    // Precompute character coordinates on the 6x5 keyboard
    // 'A' -> (0,0), 'B' -> (0,1), ..., 'F' -> (0,5)
    // 'G' -> (1,0), ..., 'L' -> (1,5)
    // ...
    // 'Z' -> (4,1) (since 26 chars, 25 is 0-indexed. 25 / 6 = 4, 25 % 6 = 1)
    private static int[][] charCoords = new int[26][2];

    static {
        for (int i = 0; i < 26; i++) {
            charCoords[i][0] = i / 6; // row
            charCoords[i][1] = i % 6; // column
        }
    }

    // Calculate Manhattan distance between two key positions
    private int getDistance(int p1, int p2) {
        // p1 and p2 are 0-25 representing 'A'-'Z'
        int r1 = charCoords[p1][0];
        int c1 = charCoords[p1][1];
        int r2 = charCoords[p2][0];
        int c2 = charCoords[p2][1];
        return Math.abs(r1 - r2) + Math.abs(c1 - c2);
    }

    public int minimumDistance(String word) {
        int n = word.length();
        // dp[k][f1_pos][f2_pos] stores the minimum cost to type word[0...k-1]
        // such that one finger is at f1_pos and the other at f2_pos.
        // f1_pos and f2_pos range from 0-25 (for 'A'-'Z') or 26 (for OFF_KEYBOARD).
        // Using 27 for array size to accommodate index 26.
        int[][][] dp = new int[n + 1][27][27];

        // Initialize dp table with a large value
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j < 27; j++) {
                Arrays.fill(dp[i][j], Integer.MAX_VALUE / 2); // Use /2 to prevent overflow on addition
            }
        }

        // Base case: Before typing any character (k=0), both fingers are off the keyboard.
        // Cost is 0.
        int OFF_KEYBOARD = 26;
        dp[0][OFF_KEYBOARD][OFF_KEYBOARD] = 0;

        // Iterate through each character in the word
        for (int k = 0; k < n; k++) {
            int currCharPos = word.charAt(k) - 'A'; // Position of the current character to type

            // Iterate through all possible previous finger positions
            for (int prevF1Pos = 0; prevF1Pos < 27; prevF1Pos++) {
                for (int prevF2Pos = 0; prevF2Pos < 27; prevF2Pos++) {
                    if (dp[k][prevF1Pos][prevF2Pos] == Integer.MAX_VALUE / 2) {
                        continue; // This state is unreachable
                    }

                    // Option 1: Use finger 1 to type word[k]
                    int cost1 = (prevF1Pos == OFF_KEYBOARD) ? 0 : getDistance(prevF1Pos, currCharPos);
                    int newCost1 = dp[k][prevF1Pos][prevF2Pos] + cost1;
                    // Update the next state: finger 1 moves to currCharPos, finger 2 stays at prevF2Pos
                    dp[k + 1][currCharPos][prevF2Pos] = Math.min(dp[k + 1][currCharPos][prevF2Pos], newCost1);

                    // Option 2: Use finger 2 to type word[k]
                    int cost2 = (prevF2Pos == OFF_KEYBOARD) ? 0 : getDistance(prevF2Pos, currCharPos);
                    int newCost2 = dp[k][prevF1Pos][prevF2Pos] + cost2;
                    // Update the next state: finger 1 stays at prevF1Pos, finger 2 moves to currCharPos
                    dp[k + 1][prevF1Pos][currCharPos] = Math.min(dp[k + 1][prevF1Pos][currCharPos], newCost2);
                }
            }
        }

        // After processing all characters, find the minimum cost among all possible final finger positions
        int minTotalDistance = Integer.MAX_VALUE;
        for (int f1Pos = 0; f1Pos < 27; f1Pos++) {
            for (int f2Pos = 0; f2Pos < 27; f2Pos++) {
                minTotalDistance = Math.min(minTotalDistance, dp[n][f1Pos][f2Pos]);
            }
        }

        return minTotalDistance;
    }
}
