import java.util.Arrays;
import java.util.Comparator;

class Solution {
    public int carFleet(int target, int[] position, int[] speed) {
        int n = position.length;
        if (n == 0) {
            return 0;
        }

        // 创建一个二维数组来存储每辆车的 [位置, 速度]
        // 使用 double 是为了避免浮点数除法时可能出现的精度问题，虽然这里用 int 也可以，但 double 更通用
        double[][] cars = new double[n][2];
        for (int i = 0; i < n; i++) {
            cars[i][0] = position[i];
            cars[i][1] = speed[i];
        }

        // 按照车辆的位置从大到小排序（即从离终点最近的开始处理）
        Arrays.sort(cars, (a, b) -> Double.compare(b[0], a[0]));

        int fleetCount = 0;
        // 记录当前最前面车队（或单车）到达终点所需的时间
        // 初始值为0.0，确保第一辆车（最接近终点）总会形成一个新车队
        double currentTimeToTarget = 0.0;

        // 遍历排序后的车辆
        for (int i = 0; i < n; i++) {
            double pos = cars[i][0];
            double spd = cars[i][1];

            // 计算当前车辆到达终点所需的时间
            double time = (target - pos) / spd;

            // 如果当前车辆到达终点的时间比当前最前面车队的时间更晚，
            // 说明它无法追上前面的车队，因此会形成一个新的车队。
            if (time > currentTimeToTarget) {
                fleetCount++;
                currentTimeToTarget = time; // 更新当前最前面车队的时间为这个新车队的时间
            }
            // 如果当前车辆到达终点的时间小于或等于当前最前面车队的时间，
            // 说明它会追上前面的车队并加入其中。此时，车队到达终点的时间
            // 仍然由最慢的那辆车（即 currentTimeToTarget 所代表的车队）决定，
            // 所以 currentTimeToTarget 不需要更新。
        }

        return fleetCount;
    }
}

