class Solution {
    public int search(int[] nums, int target) {
        int left = 0;
        int right = nums.length - 1; // 搜索区间是 [left, right] （闭区间）

        while (left <= right) { // 当 left <= right 时，搜索区间有效
            // 防止 left + right 溢出，等价于 (left + right) / 2
            int mid = left + (right - left) / 2; 

            if (nums[mid] == target) {
                return mid; // 找到目标值
            } else if (nums[mid] < target) {
                left = mid + 1; // 目标值在右半部分，排除 mid
            } else { // nums[mid] > target
                right = mid - 1; // 目标值在左半部分，排除 mid
            }
        }

        return -1; // 未找到目标值
    }
}
