import java.util.HashMap;
import java.util.Map;

class LRUCache {

    // 定义双向链表节点
    class Node {
        int key;
        int value;
        Node prev;
        Node next;

        public Node(int key, int value) {
            this.key = key;
            this.value = value;
        }
    }

    private Map<Integer, Node> cache; // 存储 key 到 Node 的映射，实现 O(1) 查找
    private int capacity;             // 缓存容量
    private Node head;                // 虚拟头节点，指向最近使用的节点
    private Node tail;                // 虚拟尾节点，指向最久未使用的节点

    public LRUCache(int capacity) {
        this.capacity = capacity;
        cache = new HashMap<>();
        head = new Node(0, 0); // 使用虚拟节点简化边界处理
        tail = new Node(0, 0); // 使用虚拟节点简化边界处理
        head.next = tail;
        tail.prev = head;
    }

    public int get(int key) {
        if (!cache.containsKey(key)) {
            return -1;
        }
        Node node = cache.get(key);
        moveToHead(node); // 节点被访问，移动到链表头部（最新使用）
        return node.value;
    }

    public void put(int key, int value) {
        if (cache.containsKey(key)) {
            // 如果 key 已存在，更新值并移动到头部
            Node node = cache.get(key);
            node.value = value;
            moveToHead(node);
        } else {
            // 如果 key 不存在，创建新节点
            Node newNode = new Node(key, value);
            cache.put(key, newNode);
            addNode(newNode); // 添加到链表头部

            // 如果缓存超出容量，移除最久未使用的节点
            if (cache.size() > capacity) {
                Node lruNode = popTail(); // 移除尾部节点（最久未使用）
                cache.remove(lruNode.key);
            }
        }
    }

    // --- 双向链表操作辅助方法 ---

    // 将节点添加到链表头部（在虚拟头节点head之后）
    private void addNode(Node node) {
        node.prev = head;
        node.next = head.next;
        head.next.prev = node;
        head.next = node;
    }

    // 从链表中移除一个节点
    private void removeNode(Node node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    // 将一个已存在的节点移动到链表头部
    private void moveToHead(Node node) {
        removeNode(node);
        addNode(node);
    }

    // 移除并返回链表尾部节点（最久未使用的节点，在虚拟尾节点tail之前）
    private Node popTail() {
        Node res = tail.prev;
        removeNode(res);
        return res;
    }
}
