        // 最小速度是1 (每小时至少吃一根)
        int low = 1;
        // 最大速度是香蕉堆中最大的那一堆的数量 (最坏情况，每小时吃完一整堆最大的香蕉堆)
        int high = 0;
        for (int pile : piles) {
            high = Math.max(high, pile);
        }

        int ans = high; // 存储最终结果，初始化为最大可能速度

        // 二分查找
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (canFinish(piles, mid, h)) {
                // 如果当前速度 mid 可以吃完，说明 mid 可能是一个答案
                // 尝试更小的速度，所以将 mid 记录为当前最佳答案，并缩小搜索范围到 [low, mid - 1]
                ans = mid;
                high = mid - 1;
            } else {
                // 如果当前速度 mid 不能吃完，说明速度太慢了
                // 需要提高速度，所以将搜索范围缩小到 [mid + 1, high]
                low = mid + 1;
            }
        }

        return ans;
    }

    /**
     * 辅助函数：判断Koko能否以给定速度 k 在 h 小时内吃完所有香蕉
     */
    private boolean canFinish(int[] piles, int k, int h) {
        long hoursNeeded = 0; // 注意这里用 long，防止小时数累加溢出
        for (int pile : piles) {
            // 计算吃完当前这堆香蕉所需的小时数
            // 向上取整：(pile + k - 1) / k
            hoursNeeded += (pile + k - 1) / k;
            // 如果所需总小时数已经超过 h，则直接返回 false
            if (hoursNeeded > h) {
                return false;
            }
        }
        return true; // 所有香蕉都能在 h 小时内吃完
    }
}

