class Solution {
    public int maxDistance(int[] colors) {
        int n = colors.length;
        int maxDist = 0;

        // 情况1：其中一个房子是索引0的房子
        // 从数组末尾向前遍历，找到第一个与colors[0]颜色不同的房子
        // 这样可以确保找到的是离索引0最远的房子
        for (int j = n - 1; j >= 0; j--) {
            if (colors[j] != colors[0]) {
                maxDist = Math.max(maxDist, j - 0);
                break; // 找到最远的了，无需继续向前找
            }
        }

        // 情况2：其中一个房子是索引n-1的房子
        // 从数组开头向后遍历，找到第一个与colors[n-1]颜色不同的房子
        // 这样可以确保找到的是离索引n-1最远的房子
        for (int i = 0; i < n; i++) {
            if (colors[i] != colors[n - 1]) {
                maxDist = Math.max(maxDist, (n - 1) - i);
                break; // 找到最远的了，无需继续向后找
            }
        }

        return maxDist;
    }
}
