```java
class Solution {
    public int findMin(int[] nums) {
        if (nums == null || nums.length == 0) {
            // 根据实际问题要求，可以抛出异常或返回特定值
            throw new IllegalArgumentException("Input array cannot be null or empty.");
        }

        int left = 0;
        int right = nums.length - 1;

        // 当数组未旋转（或旋转了n次）时，第一个元素就是最小值。
        // 这种情况下，nums[left] <= nums[right] 成立。
        // 即使没有这个提前判断，下面的二分查找逻辑也能正确处理。
        if (nums[left] <= nums[right]) {
            return nums[left];
        }

        while (left < right) {
            int mid = left + (right - left) / 2;

            // 如果 nums[mid] > nums[right]，说明 mid 位于旋转点之前。
            // 最小值一定在 mid 的右侧（包括 mid+1 到 right）。
            // 例如：[3,4,5,1,2]，mid=5，right=2。nums[mid](5) > nums[right](2)。
            // 最小值在 [1,2] 中，所以 left = mid + 1。
            if (nums[mid] > nums[right]) {
                left = mid + 1;
            }
            // 如果 nums[mid] < nums[right]，说明 mid 位于旋转点之后，或者 mid 就是最小值。
            // 此时，从 mid 到 right 的部分是有序的。
            // 最小值可能就是 nums[mid]，或者在 mid 的左侧（left 到 mid-1）。
            // 所以我们将 right 移动到 mid。不能是 mid-1，因为 nums[mid] 可能是最小值。
            // 例如：[4,5,1,2,3]，mid=1，right=3。nums[mid](1) < nums[right](3)。
            // 最小值在 [4,5,1] 中，所以 right = mid。
            else { // nums[mid] < nums[right]
                right = mid;
            }
        }

        // 当循环结束时，left 和 right 会指向同一个索引，该索引处的元素就是最小值。
        return nums[left];
    }
}
