class Solution {
    public int search(int[] nums, int target) {
        if (nums == null || nums.length == 0) {
            return -1;
        }

        int low = 0;
        int high = nums.length - 1;

        while (low <= high) {
            int mid = low + (high - low) / 2;

            if (nums[mid] == target) {
                return mid;
            }

            // Check if the left half is sorted (nums[low] to nums[mid])
            if (nums[low] <= nums[mid]) {
                // If target is within the sorted left half
                if (nums[low] <= target && target < nums[mid]) {
                    high = mid - 1; // Search in the left half
                } else {
                    low = mid + 1; // Target is in the right half (unsorted or sorted part beyond mid)
                }
            } 
            // Else, the right half is sorted (nums[mid] to nums[high])
            else {
                // If target is within the sorted right half
                if (nums[mid] < target && target <= nums[high]) {
                    low = mid + 1; // Search in the right half
                } else {
                    high = mid - 1; // Target is in the left half (unsorted or sorted part before mid)
                }
            }
        }

        return -1; // Target not found
    }
}
